from locust import HttpUser

from typing import Dict

from genai_bench.logging import init_logger
from genai_bench.metrics.request_metrics_collector import RequestMetricsCollector
from genai_bench.protocol import UserRequest, UserResponse

logger = init_logger(__name__)


class BaseUser(HttpUser):
    supported_tasks: Dict[str, str] = {}

    def __new__(cls, *args, **kwargs):
        if cls is BaseUser:
            raise TypeError("BaseUser is not meant to be instantiated directly.")
        return super().__new__(cls)

    def __init__(self, *args, **kwargs) -> None:
        super().__init__(*args, **kwargs)

    @classmethod
    def is_task_supported(cls, task: str) -> bool:
        return task in cls.supported_tasks

    def sample(self) -> UserRequest:
        if not (
            hasattr(self.environment, "scenario")
            and self.environment.scenario is not None
        ):
            raise AttributeError(
                f"Environment {self.environment} has no attribute "
                f"'scenario' or it is empty."
            )
        if not (
            hasattr(self.environment, "sampler")
            and self.environment.sampler is not None
        ):
            raise AttributeError(
                f"Environment {self.environment} has no attribute "
                f"'sampler' or it is empty."
            )
        return self.environment.sampler.sample(self.environment.scenario)

    def collect_metrics(
        self,
        user_response: UserResponse,
        endpoint: str,
    ):
        """
        Collects metrics based on the UserResponse.

        Args:
            user_response (UserResponse): The response object containing the
                request metrics.
            endpoint (str): The API endpoint for the request.
        """
        request_metrics_collector = RequestMetricsCollector()
        if user_response.status_code == 200:
            request_metrics_collector.calculate_metrics(user_response)
            self.environment.events.request.fire(
                request_type="POST",
                name=endpoint,
                response_time=request_metrics_collector.metrics.e2e_latency,
                response_length=request_metrics_collector.metrics.num_output_tokens,
            )
        else:
            # Handle error responses
            request_metrics_collector.metrics.error_code = user_response.status_code
            request_metrics_collector.metrics.error_message = (
                user_response.error_message
            )
            self.environment.events.request.fire(
                request_type="POST",
                name=endpoint,
                response_time=0,
                response_length=0,
                exception=f"Request failed with "
                f"status {user_response.status_code}, "
                f"message: {user_response.error_message}",
            )
            logger.warning(
                f"Received error response from server. Error code:"
                f" {user_response.status_code},"
                f" message: {user_response.error_message}."
            )

        # Send metrics to aggregated_metrics_collector
        self.environment.runner.send_message(
            "request_metrics", request_metrics_collector.metrics.model_dump_json()
        )  # type: ignore[attr-defined]

"""Factory for creating storage providers."""

from genai_bench.auth.storage_auth_provider import StorageAuthProvider
from genai_bench.storage.base import BaseStorage


class StorageFactory:
    """Factory for creating storage provider instances."""

    @staticmethod
    def create_storage(
        provider: str, auth: StorageAuthProvider, **kwargs
    ) -> BaseStorage:
        """Create a storage provider instance.

        Args:
            provider: Storage provider type ('oci', 'aws', 'azure', 'gcp', 'github')
            auth: Storage authentication provider
            **kwargs: Additional provider-specific configuration

        Returns:
            BaseStorage instance

        Raises:
            ValueError: If provider is not supported
        """
        storage_type = auth.get_storage_type()

        # Validate provider matches auth type
        if provider != storage_type:
            raise ValueError(
                f"Storage provider '{provider}' does not match auth type "
                f"'{storage_type}'"
            )

        if provider == "oci":
            # Lazy import to avoid requiring OCI SDK if not used
            from genai_bench.storage.oci_storage import OCIObjectStorage

            return OCIObjectStorage(auth, **kwargs)
        elif provider == "aws":
            # Lazy import to avoid requiring AWS SDK if not used
            from genai_bench.storage.aws_storage import AWSS3Storage

            return AWSS3Storage(auth, **kwargs)
        elif provider == "azure":
            # Lazy import to avoid requiring Azure SDK if not used
            from genai_bench.storage.azure_storage import AzureBlobStorage

            return AzureBlobStorage(auth, **kwargs)
        elif provider == "gcp":
            # Lazy import to avoid requiring GCP SDK if not used
            from genai_bench.storage.gcp_storage import GCPCloudStorage

            return GCPCloudStorage(auth, **kwargs)
        elif provider == "github":
            # Lazy import to avoid requiring GitHub SDK if not used
            from genai_bench.storage.github_storage import GitHubStorage

            return GitHubStorage(auth, **kwargs)
        else:
            raise ValueError(
                f"Unsupported storage provider: {provider}. "
                f"Supported: oci, aws, azure, gcp, github"
            )

"""Factory for creating appropriate data loaders and loading data."""

from typing import Any, List, Tuple, Union, cast

from genai_bench.data.config import DatasetConfig
from genai_bench.data.loaders.image import ImageDatasetLoader
from genai_bench.data.loaders.text import TextDatasetLoader
from genai_bench.logging import init_logger

logger = init_logger(__name__)


class DataLoaderFactory:
    """Factory for creating data loaders and loading data."""

    @staticmethod
    def load_data_for_task(
        task: str, dataset_config: DatasetConfig
    ) -> Union[List[str], List[Tuple[str, Any]]]:
        """Load data for a specific task.

        Args:
            task: Task name in format "input-to-output"
            dataset_config: Dataset configuration

        Returns:
            Loaded data for the task
        """
        input_modality, output_modality = task.split("-to-")

        if input_modality == "text":
            return DataLoaderFactory._load_text_data(dataset_config, output_modality)
        elif "image" in input_modality:
            return DataLoaderFactory._load_image_data(dataset_config)
        else:
            raise ValueError(f"Unsupported input modality: {input_modality}")

    @staticmethod
    def _load_text_data(
        dataset_config: DatasetConfig, output_modality: str
    ) -> List[str]:
        """Load text data."""

        loader = TextDatasetLoader(dataset_config)
        data = loader.load_request()

        # TextDatasetLoader always returns List[str]
        text_data = cast(List[str], data)
        return text_data

    @staticmethod
    def _load_image_data(
        dataset_config: DatasetConfig,
    ) -> List[Tuple[str, Any]]:
        """Load image data."""
        loader = ImageDatasetLoader(dataset_config)
        data = loader.load_request()
        return data  # type: ignore

