    @classmethod
    def apply_time_unit_conversion(
        cls, config_data: Dict[str, Any], metrics_time_unit: str = "s"
    ) -> Dict[str, Any]:
        """
        Apply time unit conversion to plot configuration labels.

        Args:
            config_data: Plot configuration dictionary
            metrics_time_unit: Target time unit ('s' or 'ms')

        Returns:
            Modified configuration with updated labels
        """
        if metrics_time_unit not in ["s", "ms"]:
            return config_data

        # Create a copy to avoid modifying the original
        config_copy = config_data.copy()

        # Convert labels in each plot specification
        for plot_copy in config_copy.get("plots", []):
            # Convert title
            if "title" in plot_copy:
                original_title = plot_copy["title"]
                plot_copy["title"] = TimeUnitConverter.get_unit_label(
                    original_title, metrics_time_unit
                )

            # Convert y_label
            if "y_label" in plot_copy:
                original_y_label = plot_copy["y_label"]
                plot_copy["y_label"] = TimeUnitConverter.get_unit_label(
                    original_y_label, metrics_time_unit
                )

            # Convert x_label
            if "x_label" in plot_copy:
                original_x_label = plot_copy["x_label"]
                plot_copy["x_label"] = TimeUnitConverter.get_unit_label(
                    original_x_label, metrics_time_unit
                )

            # Convert y_fields labels
            if "y_fields" in plot_copy:
                for y_field in plot_copy["y_fields"]:
                    if "label" in y_field:
                        original_label = y_field["label"]
                        y_field["label"] = TimeUnitConverter.get_unit_label(
                            original_label, metrics_time_unit
                        )

        return config_copy

    @classmethod
    def load_config(
        cls, config_source: Union[str, Dict, None] = None, metrics_time_unit: str = "s"
    ) -> PlotConfig:
        """Load plot configuration from various sources."""
        if config_source is None:
            # Use default 2x4 preset
            return cls.load_preset("2x4_default", metrics_time_unit)

        if isinstance(config_source, str):
            if config_source in cls.PRESETS:
                # Load preset
                return cls.load_preset(config_source, metrics_time_unit)
            else:
                # Load from file
                return cls.load_from_file(config_source, metrics_time_unit)

        if isinstance(config_source, dict):
            # Load from dictionary
            converted_data = cls.apply_time_unit_conversion(
                config_source, metrics_time_unit
            )
            return PlotConfig(**converted_data)

        raise ValueError(f"Invalid config source type: {type(config_source)}")

    @classmethod
    def load_preset(cls, preset_name: str, metrics_time_unit: str = "s") -> PlotConfig:
        """Load a preset plot configuration."""
        if preset_name not in cls.PRESETS:
            raise ValueError(
                f"Unknown preset: {preset_name}. Available: {list(cls.PRESETS.keys())}"
            )

        preset_data = cls.PRESETS[preset_name]
        return cls.load_config(preset_data, metrics_time_unit)

    @classmethod
    def load_from_file(cls, file_path: str, metrics_time_unit: str = "s") -> PlotConfig:
        """Load configuration from JSON file."""
        path = Path(file_path)
        if not path.exists():
            raise FileNotFoundError(f"Plot config file not found: {file_path}")

        try:
            with open(path, "r") as f:
                config_data = json.load(f)
            converted_data = cls.apply_time_unit_conversion(
                config_data, metrics_time_unit
            )
            return PlotConfig(**converted_data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON in config file {file_path}: {e}") from e
        except Exception as e:
            raise ValueError(f"Error loading config from {file_path}: {e}") from e

    @classmethod
    def save_config(cls, config: PlotConfig, file_path: str) -> None:
        """Save configuration to JSON file."""
        path = Path(file_path)
        path.parent.mkdir(parents=True, exist_ok=True)

        with open(path, "w") as f:
            json.dump(config.model_dump(), f, indent=2)

    @classmethod
    def get_available_fields(cls) -> Dict[str, str]:
        """Get all available fields from AggregatedMetrics."""
        fields = {}

        # Direct fields
        for field_name, field_info in AggregatedMetrics.model_fields.items():
            if field_name != "stats":
                fields[field_name] = field_info.description or field_name

        # Stats fields with statistical measures
        stats_measures = [
            "min",
            "max",
            "mean",
            "stddev",
            "sum",
            "p25",
            "p50",
            "p75",
            "p90",
            "p95",
            "p99",
        ]
        stats_fields = [
            "ttft",
            "tpot",
            "e2e_latency",
            "output_latency",
            "output_inference_speed",
            "num_input_tokens",
            "num_output_tokens",
            "num_reasoning_tokens",
            "total_tokens",
            "input_throughput",
            "output_throughput",
        ]

        for field in stats_fields:
            for measure in stats_measures:
                field_path = f"stats.{field}.{measure}"
                fields[field_path] = f"{field} {measure}"

        return fields

    @classmethod
    def get_fields_from_data(
        cls, metrics: AggregatedMetrics
    ) -> Dict[str, Tuple[Any, str]]:
        """
        Extract available fields with actual values from real experiment data.

        Returns:
            Dict mapping field_path -> (value, type_name)
        """
        available_fields = {}

        # Direct fields from AggregatedMetrics
        for field_name in AggregatedMetrics.model_fields:
            if field_name == "stats":
                continue

            try:
                value = getattr(metrics, field_name)
                if value is not None:
                    field_type = type(value).__name__
                    available_fields[field_name] = (value, field_type)
            except AttributeError:
                continue

        # Stats fields - check which ones have actual data
        if hasattr(metrics, "stats") and metrics.stats is not None:
            stats = metrics.stats

            # Get available stat fields from the stats object
            for stat_field_name in stats.model_fields:
                try:
                    stat_field = getattr(stats, stat_field_name)
                    if stat_field is not None:
                        # Check each statistical measure
                        for measure_name in stat_field.model_fields:
                            try:
                                measure_value = getattr(stat_field, measure_name)
                                if measure_value is not None:
                                    field_path = (
                                        f"stats.{stat_field_name}.{measure_name}"
                                    )
                                    field_type = type(measure_value).__name__
                                    available_fields[field_path] = (
                                        measure_value,
                                        field_type,
                                    )
                            except AttributeError:
                                continue
                except AttributeError:
                    continue

        return available_fields

    @classmethod
    def validate_field_path(
        cls, field_path: str, sample_metrics: AggregatedMetrics
    ) -> bool:
        """Validate that a field path exists in AggregatedMetrics."""
        try:
            value = cls.get_field_value(sample_metrics, field_path)
            return value is not None
        except Exception:
            return False

    @classmethod
    def get_field_value(cls, metrics: AggregatedMetrics, field_path: str) -> Any:
        """Get value from metrics using field path (e.g., 'stats.ttft.mean')."""
        parts = field_path.split(".")
        value = metrics

        for part in parts:
            if hasattr(value, part):
                value = getattr(value, part)
            else:
                raise AttributeError(f"Field path '{field_path}' not found")

        return value

